export interface JxlCache {
  init(): Promise<void>;
  get(key: string): Promise<ArrayBuffer | undefined>;
  set(key: string, buffer: ArrayBuffer): Promise<void>;
  delete(key: string): Promise<void>;
  has(key: string): Promise<boolean>;
  clear(): Promise<void>;
  stats(): any;   // <-- untyped
}

// node.ts stats() returns:
persistent: {
  count: ..., size: ..., limit: ...,
  enabled: ...,
  evictions: this.evictionsCount
  // quotaEvictions missing
}

// browser.ts stats() returns:
persistent: {
  ...,
  evictions: this.evictionsCount,
  quotaEvictions: this.quotaEvictionsCount  // present only here
}

async has(key: string): Promise<boolean> {
  if (this.initPromise) await this.initPromise.catch(() => undefined);
  if (this.memoryCache.has(key)) return true;
  if (this.persistentTracker.has(key)) return true;  // stale tracker
  return false;
}

for (const entry of manifest.entries) {
  if (
    typeof entry.key === 'string' &&
    typeof entry.name === 'string' &&  // no length check
    Number.isFinite(entry.size) && entry.size >= 0
  ) {
    this.persistentTracker.set(entry.key, { name: entry.name }, entry.size);
  }
}

const files = await fs.readdir(this.opts.basePath);
await Promise.allSettled(
  files.map((file) => fs.unlink(path.join(this.opts.basePath!, file)))
  // deletes ALL files regardless of origin
);

private async doInit(): Promise<void> {
  if (this.opts.persistent && this.opts.basePath) {
    // only enters when both set
    await fs.mkdir(this.opts.basePath, { recursive: true });
    ...
  }
  // otherwise silently returns — no warning
}

export interface JxlCache {
  ...
  stats(): any;  // no exported CacheStats type
}

private scheduleManifestWrite(): void {
  this.manifestDirty = true;
  if (this.manifestPendingWrite !== null) return;
  this.manifestPendingWrite = new Promise(resolve => setTimeout(resolve, 250))
    .then(() => this.drainManifest())
    .finally(() => { this.manifestPendingWrite = null; });
  // no way to flush synchronously from outside
}

// browser.ts get() — waits for inflight set
const ps = this.inflightSets.get(key);
if (ps) await ps.catch(() => undefined);

// node.ts get() — no such wait; goes straight to:
const pending = this.getPersistent(key);
this.inflightGets.set(key, pending);
